def call(env)
  request = Rack::Request.new(env)
  client_key = identify_client(request)
  key = "rate_limit:#{client_key}"

  count = @redis.get(key).to_i

  if count < @limit
    @redis.incr(key)
    @redis.expire(key, @window_seconds)
    @logger.debug("Rate limit: #{client_key} => #{count + 1}/#{@limit}")
    @app.call(env)
  else
    @logger.warn("Rate limit exceeded for #{client_key}")
    rate_limit_response(count)
  end
end
